Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: injectable mock handler
    private static HttpClient CreateClient(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        return new HttpClient(new MockHandler(handler));
    }

    private class MockHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken ct) => handler(request, ct);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var fetcher = new DataFetcher(client);
        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpFailure()
    {
        using var client = CreateClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.InternalServerError)));

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // --- Cancellation ---
    [TestMethod]
    public async Task FetchAsync_Throws_WhenAlreadyCancelled()
    {
        using var client = CreateClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)));

        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel before calling

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelledDuringRequest()
    {
        using var cts = new CancellationTokenSource();

        using var client = CreateClient(async (_, ct) =>
        {
            cts.Cancel();            // simulate: cancel while "in flight"
            ct.ThrowIfCancellationRequested();
            return new HttpResponseMessage(System.Net.HttpStatusCode.OK);
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Timeout ---
    [TestMethod]
    [Timeout(3000)] // MSTest hard guard — fails the test if it hangs
    public async Task FetchAsync_Throws_WhenTimeoutExpires()
    {
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        using var client = CreateClient(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct); // simulate slow server
            return new HttpResponseMessage(System.Net.HttpStatusCode.OK);
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }
}
```

**Key patterns demonstrated:**

| Concern | Technique |
|---|---|
| **Mock HTTP** | Custom `HttpMessageHandler` — no external packages needed |
| **Pre-cancelled token** | `cts.Cancel()` before the call |
| **Mid-flight cancel** | Cancel inside the handler delegate |
| **Timeout** | `new CancellationTokenSource(TimeSpan)` creates a self-cancelling token |
| **Hang protection** | `[Timeout(3000)]` on the test method as a safety net |

**Gotcha to watch for:** `TaskCanceledException` is a subclass of `OperationCanceledException`. If your production code ever catches `OperationCanceledException`, test for that base type instead.
